import pandas as pd
df = pd.DataFrame({'cliente_id': ['C001'], 'region': ['Lima'], 'score': [1.0]})
sub = df[df.cliente_id == 'C001']
if len(sub) > 1 and bool(sub.duplicated(keep=False).all()):
    print('exact')
elif sub['region'].nunique() > 1:
    print('conflict')
else:
    print('clean')
